import React, { useState } from "react";

// Dentes permanentes e decíduos (FDI)
const dentesPermanentes = [
  [18, 17, 16, 15, 14, 13, 12, 11, 21, 22, 23, 24, 25, 26, 27, 28],
  [48, 47, 46, 45, 44, 43, 42, 41, 31, 32, 33, 34, 35, 36, 37, 38]
];

const dentesDeciduos = [
  ['55', '54', '53', '52', '51', '61', '62', '63', '64', '65'],
  ['85', '84', '83', '82', '81', '71', '72', '73', '74', '75']
];

// Legenda de status
const statusLegenda = {
  aberto: { cor: "#fbbf24", texto: "Aberto 🦷" },
  finalizado: { cor: "#a3e635", texto: "Finalizado 🦷" },
  anotacao: { cor: "#6366f1", texto: "Anotações !" }
};
const ordemStatus = ["aberto", "finalizado", "anotacao", ""]; // "" = sem status

export default function OdontogramaAvancado() {
  const [aba, setAba] = useState("permanentes");
  const [status, setStatus] = useState({});
  const dentes = aba === "permanentes" ? dentesPermanentes : dentesDeciduos;

  function handleDenteClick(num) {
    const atual = status[num] || "";
    const next =
      ordemStatus[(ordemStatus.indexOf(atual) + 1) % ordemStatus.length];
    setStatus({ ...status, [num]: next });
  }

  return (
    <div className="p-2">
      {/* Abas */}
      <div className="flex mb-4 gap-2">
        <button
          className={`px-4 py-1 rounded ${
            aba === "permanentes"
              ? "bg-blue-600 text-white"
              : "bg-gray-200 text-gray-700"
          }`}
          onClick={() => setAba("permanentes")}
        >
          Permanentes
        </button>
        <button
          className={`px-4 py-1 rounded ${
            aba === "deciduos"
              ? "bg-blue-600 text-white"
              : "bg-gray-200 text-gray-700"
          }`}
          onClick={() => setAba("deciduos")}
        >
          Decíduos
        </button>
      </div>

      {/* Dentes */}
      <div className="mb-4">
        {dentes.map((linha, idx) => (
          <div
            key={idx}
            className="flex items-end justify-center gap-1 mb-2"
            style={{ minHeight: 60 }}
          >
            {linha.map((num, j) => (
              <div
                key={num}
                className="flex flex-col items-center group"
                style={{ width: 38 }}
              >
                <svg
                  width="34"
                  height="44"
                  viewBox="0 0 34 44"
                  onClick={() => handleDenteClick(num)}
                  style={{
                    cursor: "pointer",
                    stroke: status[num]
                      ? statusLegenda[status[num]]?.cor || "#fbbf24"
                      : "#bbb",
                    strokeWidth: 2,
                    fill: "none",
                    transition: "stroke 0.2s"
                  }}
                >
                  {/* Forma simplificada de dente */}
                  <path
                    d="M8 42 Q5 25 5 15 Q5 2 17 2 Q29 2 29 15 Q29 25 26 42"
                    style={{
                      stroke: status[num]
                        ? statusLegenda[status[num]]?.cor || "#fbbf24"
                        : "#bbb",
                      fill: status[num]
                        ? statusLegenda[status[num]]?.cor + "22"
                        : "none"
                    }}
                  />
                </svg>
                <span
                  className="text-xs mt-1"
                  style={{
                    fontWeight: status[num] ? 700 : 400,
                    color: status[num]
                      ? statusLegenda[status[num]]?.cor
                      : "#888"
                  }}
                >
                  {num}
                </span>
              </div>
            ))}
          </div>
        ))}
      </div>

      {/* Filtros (placeholders, sem ação real ainda) */}
      <div className="flex gap-2 mb-2 flex-wrap">
        <Filtro label="Maxila" />
        <Filtro label="Mandíbula" />
        <Filtro label="Face" />
        <Filtro label="Arcada superior" />
        <Filtro label="Arcada inferior" />
        <Filtro label="Arcadas" />
      </div>

      <hr className="my-4" />

      {/* Legenda */}
      <div className="flex gap-4">
        {Object.entries(statusLegenda).map(([key, val]) => (
          <div key={key} className="flex items-center gap-1">
            <input
              type="checkbox"
              checked
              readOnly
              style={{ accentColor: val.cor }}
            />
            <span style={{ color: val.cor }}>{val.texto}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

// Componente filtro (só visual)
function Filtro({ label }) {
  return (
    <button
      type="button"
      className="px-4 py-1 rounded-full bg-gray-100 text-gray-700 border border-gray-300 text-sm"
      tabIndex={-1}
    >
      {label}
    </button>
  );
}
